         import sailpoint.object.Identity;
          import sailpoint.tools.Util;

          String termValue = ""; 

          if (Util.isNotNullOrEmpty(identityName)) {
          Identity idn = context.getObjectByName(Identity.class, identityName);
          if (idn != null) {
          termValue = idn.getFirstname();
          //comment decache //context.decache(idn);
          }
          }
          return termValue;

  
          		
